import subprocess
# Get all symbols sorted by address
result = subprocess.run(['nm', '-n', '-C', '_.debug'], capture_output=True, text=True)
lines = result.stdout.strip().splitlines()
targets = [0x2f4b20, 0x2f4c84]
for t in targets:
    prev = None
    for line in lines:
        parts = line.split(None, 2)
        if len(parts) >= 3:
            try:
                addr = int(parts[0], 16)
                if addr > t:
                    if prev:
                        print(f'0x{t:x}: {prev}')
                    else:
                        print(f'0x{t:x}: not found')
                    break
                prev = f'{parts[2]} @ 0x{addr:x} (+0x{t-addr:x})'
            except: pass
    else:
        if prev:
            print(f'0x{t:x}: {prev} (last symbol)')
" 2>&1

