for t in targets:
    print(f'--- Symbols near 0x{t:x} ---')
    prev_lines = []
    for line in lines:
        parts = line.split(None, 2)
        if len(parts) >= 3:
            try:
                addr = int(parts[0], 16)
                if abs(addr - t) <= 0x20:
                    print(f'  {line.strip()}')
                elif addr > t + 0x20:
                    break
                if addr <= t:
                    prev_lines.append(line.strip())
                    if len(prev_lines) > 3:
                        prev_lines.pop(0)
            except: pass
    if prev_lines:
        print(f'  Nearest before:')
        for pl in prev_lines:
            print(f'    {pl}')
    print()
